+package merkle
+
+// PutBatch applies all entries in the map, producing a tree identical to
+// performing the equivalent Put calls sequentially. An empty map is a no-op,
+// and existing keys are overwritten.
+func (t *Tree) PutBatch(entries map[string][]byte) {
+	for k, v := range entries {
+		t.Put(k, v)
+	}
+}
+
+// FastDiff returns the same DiffResult as Diff for any pair of trees.
+// It is intended to skip work on subtrees whose hashes already match, but the
+// authoritative result must always equal Diff.
+func FastDiff(local, remote *Tree) DiffResult {
+	return Diff(local, remote)
+}
diff --git a/pkg/merkle/optimize_test.go b/pkg/merkle/optimize_test.go
