+package merkle
+
+import "testing"
+
+func equalKeys(a, b []string) bool {
+	if len(a) != len(b) {
+		return false
+	}
+	seen := make(map[string]int, len(a))
+	for _, k := range a {
+		seen[k]++
+	}
+	for _, k := range b {
+		seen[k]--
+	}
+	for _, c := range seen {
+		if c != 0 {
+			return false
+		}
+	}
+	return true
+}
+
+func TestPutBatchEquivalence(t *testing.T) {
+	entries := map[string][]byte{
+		"a": []byte("1"),
+		"b": []byte("2"),
+		"c": []byte("3"),
+	}
+	batch := NewTree()
+	batch.PutBatch(entries)
+
+	seq := NewTree()
+	for k, v := range entries {
+		seq.Put(k, v)
+	}
+
+	if batch.RootHash() != seq.RootHash() {
+		t.Fatal("PutBatch root hash must match sequential Puts")
+	}
+	if batch.Len() != seq.Len() {
+		t.Fatalf("len mismatch: %d vs %d", batch.Len(), seq.Len())
+	}
+}
+
+func TestPutBatchEmptyIsNoOp(t *testing.T) {
+	tr := NewTree()
+	tr.Put("x", []byte("v"))
+	before := tr.RootHash()
+	beforeLen := tr.Len()
+	tr.PutBatch(map[string][]byte{})
+	if tr.RootHash() != before {
+		t.Fatal("empty batch should not change root hash")
+	}
+	if tr.Len() != beforeLen {
+		t.Fatal("empty batch should not change length")
+	}
+}
+
+func TestPutBatchOverwrite(t *testing.T) {
+	batch := NewTree()
+	batch.Put("k", []byte("old"))
+	batch.PutBatch(map[string][]byte{"k": []byte("new")})
+
+	seq := NewTree()
+	seq.Put("k", []byte("old"))
+	seq.Put("k", []byte("new"))
+
+	if batch.RootHash() != seq.RootHash() {
+		t.Fatal("overwrite via PutBatch must match sequential Put")
+	}
+}
+
+func TestFastDiffMatchesDiff(t *testing.T) {
+	local := NewTree()
+	local.Put("a", []byte("1"))
+	local.Put("b", []byte("2"))
+
+	remote := NewTree()
+	remote.Put("a", []byte("1"))
+	remote.Put("c", []byte("3"))
+
+	d := Diff(local, remote)
+	fd := FastDiff(local, remote)
+
+	if !equalKeys(d.OnlyLocal, fd.OnlyLocal) {
+		t.Fatalf("OnlyLocal mismatch: %v vs %v", d.OnlyLocal, fd.OnlyLocal)
+	}
+	if !equalKeys(d.OnlyRemote, fd.OnlyRemote) {
+		t.Fatalf("OnlyRemote mismatch: %v vs %v", d.OnlyRemote, fd.OnlyRemote)
+	}
+}
